// Simple dynamic array implementation to replace std::vector
typedef struct {
    void *data;
    size_t size;
    size_t capacity;
    size_t element_size;
} dynamic_array;

void dynamic_array_init(dynamic_array *arr, size_t element_size) {
    arr->data = NULL;
    arr->size = 0;
    arr->capacity = 0;
    arr->element_size = element_size;
}

void dynamic_array_push_back(dynamic_array *arr, const void *element) {
    if (arr->size == arr->capacity) {
        size_t new_capacity = (arr->capacity == 0) ? 1 : arr->capacity * 2;
        void *new_data = realloc(arr->data, new_capacity * arr->element_size);
        if (!new_data) {
            fprintf(stderr, "Failed to reallocate memory for dynamic array.\n");
            exit(1);
        }
        arr->data = new_data;
        arr->capacity = new_capacity;
    }
    memcpy((char *)arr->data + arr->size * arr->element_size, element, arr->element_size);
    arr->size++;
}

void *dynamic_array_get(dynamic_array *arr, size_t index) {
    if (index >= arr->size) {
        fprintf(stderr, "Index out of bounds for dynamic array.\n");
        exit(1);
    }
    return (char *)arr->data + index * arr->element_size;
}

void dynamic_array_free(dynamic_array *arr) {
    free(arr->data);
    arr->data = NULL;
    arr->size = 0;
    arr->capacity = 0;
}

