int loadData(char *filename, dynamic_array &records, dynamic_array &locations){
    FILE   *flist,*fp;
	int    i=0;
	char dbname[64];
	int recNum=0;

    /**Main processing **/

    flist = fopen(filename, "r");
	while(!feof(flist)) {
		/**
		* Read in all records of length REC_LENGTH
		* If this is the last file in the filelist, then done
		* else open next file to be read next iteration
		*/
		if(fscanf(flist, "%s\n", dbname) != 1) {
            // Check if it's just EOF without reading anything, which is fine
            if (feof(flist)) break;
            fprintf(stderr, "error reading filelist\n");
            exit(0);
        }
        fp = fopen(dbname, "r");
        if(!fp) {
            printf("error opening a db: %s\n", dbname);
            exit(1);
        }
        // read each record
        while(!feof(fp)){
            Record record;
            LatLong latLong;
            // Use fgets to read the whole line, then parse
            if (fgets(record.recString, REC_LENGTH + 1, fp) == NULL) {
                if (feof(fp)) break; // End of file
                fprintf(stderr, "error reading record from %s\n", dbname);
                exit(1);
            }

            // Check if the line read is shorter than expected, indicating potential issues or end of file
            if (strlen(record.recString) < REC_LENGTH - 1) {
                if (feof(fp)) break; // Likely end of file after a partial line
                // Handle cases where a line might be shorter but not EOF
                // For this problem, we assume fixed length records or lines ending with newline
            }

            // parse for lat and long
            char substr[6];

            // Latitude
            strncpy(substr, record.recString + LATITUDE_POS, 5);
            substr[5] = '\0';
            latLong.lat = atof(substr);

            // Longitude
            strncpy(substr, record.recString + LATITUDE_POS + 5, 5); // Assuming longitude is 5 chars after latitude
            substr[5] = '\0';
            latLong.lng = atof(substr);

            dynamic_array_push_back(&locations, &latLong);
            dynamic_array_push_back(&records, &record);
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    return recNum;
}

void findLowest(dynamic_array &records,float *distances,int numRecords,int topN){
  int i,j;
  float val;
  int minLoc;
  Record tempRec; // Use a temporary variable for swapping records
  float tempDist;

  for(i=0;i<topN;i++) { // Iterate up to topN
    minLoc = i;
    for(j=i;j<numRecords;j++) {
      val = distances[j];
      if (distances[minLoc] > val) minLoc = j;
    }
    // swap locations and distances
    // Swap records
    tempRec = *(Record*)dynamic_array_get(&records, i);
    memcpy(dynamic_array_get(&records, i), dynamic_array_get(&records, minLoc), sizeof(Record));
    memcpy(dynamic_array_get(&records, minLoc), &tempRec, sizeof(Record));


    // Swap distances
    tempDist = distances[i];
    distances[i] = distances[minLoc];
    distances[minLoc] = tempDist;

    // add distance to the min we just found
    ((Record*)dynamic_array_get(&records, i))->distance = distances[i];
  }
}

int parseCommandline(int argc, char *argv[], char* filename,int *r,float *lat,float *lng,
                     int *q, int *t, int *p, int *d){
    int i;
    if (argc < 2) return 1; // error
    strncpy(filename,argv[1],100);
    filename[99] = '\0'; // Ensure null termination
    char flag;

    for(i=1;i<argc;i++) {
      if ('-' == argv[i][0]) {// flag
        flag = argv[i][1];
          switch (flag) {
            case 'r': // number of results
              i++;
              if (i < argc) *r = atoi(argv[i]);
              else return 1; // missing argument
              break;
            case 'l': // lat or lng
              if (i+1 < argc) {
                if ('a' == argv[i][2]) {//lat
                  *lat = atof(argv[i+1]);
                }
                else if ('n' == argv[i][2]) {//lng
                  *lng = atof(argv[i+1]);
                } else {
                    return 1; // invalid flag
                }
                i++;
              } else {
                  return 1; // missing argument
              }
              break;
            case 'h': // help
              return 1;
            case 'q': // quiet
              *q = 1;
              break;
            case 't': // timing
              *t = 1;
              break;
            case 'p': // platform
              i++;
              if (i < argc) *p = atoi(argv[i]);
              else return 1; // missing argument
              break;
            case 'd': // device
              i++;
              if (i < argc) *d = atoi(argv[i]);
              else return 1; // missing argument
              break;
            default:
              return 1; // unknown flag
        }
      }
    }
    // The original CUDA code had a check for platform/device, which is not relevant for OpenMP.
    // We'll keep the structure but the checks for p and d won't have functional impact.
